     6→/**
     7→ * Tool for analyzing file structure and dependencies
     8→ */
     9→export const analyzeFileStructure = tool(
    10→  'analyze_file_structure',
    11→  'Analyzes the file and directory structure of a codebase to identify organizational patterns and potential issues',
    12→  {
    13→    directory: z.string().describe('The root directory to analyze'),
    14→    maxDepth: z.number().default(5).describe('Maximum depth to traverse (default: 5)'),
    15→  },
    16→  async (input) => {
    17→    const { directory, maxDepth = 5 } = input;
    18→
    19→    const fileTree: any = {};
    20→    const stats = {
    21→      totalFiles: 0,
    22→      totalDirs: 0,
    23→      filesByExtension: {} as Record<string, number>,
    24→    };
    25→
    26→    async function traverse(dir: string, depth: number = 0): Promise<any> {
    27→      if (depth > maxDepth) return null;
    28→
    29→      try {
    30→        const entries = await fs.readdir(dir, { withFileTypes: true });
    31→        const result: any = {};
    32→
    33→        for (const entry of entries) {
    34→          const fullPath = path.join(dir, entry.name);
    35→
    36→          // Skip node_modules and common build directories
    37→          if (entry.name === 'node_modules' || entry.name === 'dist' || entry.name === '.git') {
    38→            continue;
    39→          }
    40→
    41→          if (entry.isDirectory()) {
    42→            stats.totalDirs++;
    43→            result[entry.name] = await traverse(fullPath, depth + 1);
    44→          } else {
    45→            stats.totalFiles++;
    46→            const ext = path.extname(entry.name);
    47→            stats.filesByExtension[ext] = (stats.filesByExtension[ext] || 0) + 1;
    48→            result[entry.name] = 'file';
    49→          }
    50→        }
    51→
    52→        return result;
    53→      } catch (error) {
    54→        return { error: `Unable to read directory: ${error}` };
    55→      }
    56→    }
    57→
    58→    const tree = await traverse(directory);
    59→
    60→    return {
    61→      content: [
    62→        {
    63→          type: 'text' as const,
    64→          text: JSON.stringify({
    65→            structure: tree,
    66→            statistics: stats,
    67→            analysis: {
    68→              organizationPattern: detectOrganizationPattern(tree, stats),
    69→              suggestions: generateStructureSuggestions(stats),
    70→            },
    71→          }, null, 2),
    72→        },
    73→      ],
    74→    };
    75→  }
    76→);
    77→
    78→/**
    79→ * Tool for identifying code smells and anti-patterns
    80→ */
    81→export const identifyCodeSmells = tool(
    82→  'identify_code_smells',
    83→  'Analyzes code files to identify common code smells, anti-patterns, and architectural issues',
    84→  {
    85→    filePath: z.string().describe('Path to the file to analyze'),
    86→  },
    87→  async (input) => {
    88→    try {
    89→      const content = await fs.readFile(input.filePath, 'utf-8');
    90→      const lines = content.split('\n');
    91→
    92→      const issues: any[] = [];
    93→
    94→      // Check for large files
    95→      if (lines.length > 300) {
    96→        issues.push({
    97→          type: 'large_file',
    98→          severity: 'warning',
    99→          message: `File has ${lines.length} lines. Consider breaking it into smaller modules.`,
   100→        });
   101→      }
   102→
   103→      // Check for long functions (simple heuristic)
   104→      const functionMatches = content.match(/function\s+\w+|=>\s*{|class\s+\w+/g);
