     1→/**
     2→ * Base Agent Class
     3→ * Provides common functionality for all agents
     4→ */
     5→
     6→import {
     7→  Agent,
     8→  AgentMetadata,
     9→  AgentPromptTemplate,
    10→  AgentTools,
    11→  AgentWorkflow,
    12→  AgentExecutionContext,
    13→  AgentResult,
    14→} from '../types/agent.types';
    15→
    16→export abstract class BaseAgent implements Agent {
    17→  abstract metadata: AgentMetadata;
    18→  abstract prompt: AgentPromptTemplate;
    19→  abstract tools: AgentTools;
    20→  abstract workflow: AgentWorkflow;
    21→
    22→  async execute(context: AgentExecutionContext): Promise<AgentResult> {
    23→    const startTime = Date.now();
    24→    const result: AgentResult = {
    25→      success: false,
    26→      output: '',
    27→      artifacts: {
    28→        filesCreated: [],
    29→        filesModified: [],
    30→        filesDeleted: [],
    31→      },
    32→      metrics: {
    33→        executionTimeMs: 0,
    34→        stepsCompleted: 0,
    35→      },
    36→      errors: [],
    37→      recommendations: [],
    38→    };
    39→
    40→    try {
    41→      // Validate context
    42→      this.validateContext(context);
    43→
    44→      // Execute workflow steps
    45→      for (let i = 0; i < this.workflow.steps.length; i++) {
    46→        const step = this.workflow.steps[i];
    47→
    48→        try {
    49→          await this.executeStep(step, context, result);
    50→          result.metrics!.stepsCompleted++;
    51→        } catch (error) {
    52→          result.errors!.push({
    53→            code: `STEP_${i}_FAILED`,
    54→            message: `Failed to execute step: ${step.name}`,
    55→            details: error,
    56→          });
    57→
    58→          if (!this.canContinueOnError(step, error)) {
    59→            throw error;
    60→          }
    61→        }
    62→      }
    63→
    64→      result.success = result.errors!.length === 0;
    65→      result.output = this.generateOutput(result);
    66→
    67→    } catch (error) {
    68→      result.success = false;
    69→      result.errors!.push({
    70→        code: 'EXECUTION_FAILED',
    71→        message: error instanceof Error ? error.message : 'Unknown error',
    72→        details: error,
    73→      });
    74→    } finally {
    75→      result.metrics!.executionTimeMs = Date.now() - startTime;
    76→    }
    77→
    78→    return result;
    79→  }
    80→
    81→  protected abstract executeStep(
    82→    step: AgentWorkflow['steps'][0],
    83→    context: AgentExecutionContext,
    84→    result: AgentResult
    85→  ): Promise<void>;
    86→
    87→  protected validateContext(context: AgentExecutionContext): void {
    88→    if (!context.projectPath) {
    89→      throw new Error('Project path is required');
    90→    }
    91→    if (!context.userQuery) {
    92→      throw new Error('User query is required');
    93→    }
    94→  }
    95→
    96→  protected canContinueOnError(
    97→    step: AgentWorkflow['steps'][0],
    98→    error: unknown
    99→  ): boolean {
   100→    // Override in subclasses to define error handling strategy
   101→    return false;
   102→  }
   103→
   104→  protected generateOutput(result: AgentResult): string {
   105→    let output = `Agent: ${this.metadata.name}\n\n`;
   106→
   107→    if (result.success) {
   108→      output += '✅ Execution completed successfully\n\n';
   109→    } else {
   110→      output += '❌ Execution completed with errors\n\n';
