class ExecutionContext:
    """Lightweight execution context replacing SK's Kernel Context"""
    request_id: str
    variables: Dict[str, Any] = field(default_factory=dict)
    latency_budget_ms: float = 90.0
    stage_latencies: Dict[str, float] = field(default_factory=dict)

class PipelineStage(Generic[T, U]):
    async def execute(self, context: ExecutionContext, input_data: T) -> U:
        # Stage execution with latency tracking
        if self.skip_condition and self.skip_condition(context):
            return input_data  # Skip if condition met

        # Execute with timeout and latency tracking

class SequentialPipeline:
    """Sequential execution with conditional stage skipping"""
    async def execute(self, context: ExecutionContext, initial_input: Any) -> Any:
        for stage in self.stages:
            output = await stage.execute(context, current_output)

            if context.is_over_budget():
                break  # Early termination if SLA exceeded

class ConcurrentExecutor:
    """Parallel execution of multiple agents"""
    async def execute(
        self,
        context: ExecutionContext,
        functions: List[Callable],
        input_data: Any,
        timeout_ms: float = 100.0
    ) -> ConcurrentResult:
        tasks = [func(input_data) for func in functions]
        results = await asyncio.gather(*tasks, return_exceptions=True)
```

**Pattern:** Enables Judge #6 validation pipeline with conditional skipping to maintain p99≤90ms SLA.

