### 5. Pipeline Orchestrator - Swarm Routing & Consensus

**File:** `/Users/pikeymickey/Documents/Claude Code/Code/Claude Demo/aiyou-fastapi-services/agents/pipeline_orchestrator.py`

Implements multi-agent task distribution with Jura Protocol gating:

```python
@dataclass
class PipelineTask:
    task_id: str
    query: str
    required_specializations: List[str]
    min_agents: int = 3
    consensus_threshold: float = 0.7
    jura_gate: bool = True  # Require approval

class PipelineOrchestrator:
    def select_agents(self, task: PipelineTask) -> List[str]:
        """Select agents by specialization"""
        for spec in task.required_specializations:
            spec_agents = self.swarm.get_agents_by_specialization(spec)
            selected.extend([a.agent_id for a in spec_agents[:task.min_agents]])

    def execute_task(self, task: PipelineTask) -> Dict[str, Any]:
        # Step 1: Jura pre-gate
        if task.jura_gate:
            pre_eval = self.jura.evaluate_with_context(task.query)
            if pre_eval.get("verdict") == "DENY":
                return {"status": "blocked", "reason": "Jura pre-gate denied"}

        # Step 2: Select agents
        agent_ids = self.select_agents(task)

        # Step 3: Execute on selected agents
        for agent_id in agent_ids:
            result = TaskResult(agent_id=agent_id, confidence=0.85)
            results.append(result)

        # Step 4: Find consensus
        consensus = self._find_consensus(results, task.consensus_threshold)

        # Step 5: Jura post-gate validation
        if task.jura_gate:
            post_eval = self.jura.evaluate_with_context(json.dumps(consensus))

    def ask_swarm(self, query: str, specializations: List[str]) -> Dict[str, Any]:
        """Quick orchestration method"""
        task = PipelineTask(
            task_id=f"quick_{hash(query)}",
            query=query,
            required_specializations=specializations
        )
        return self.execute_task(task)
```

**Pattern:** Distributes tasks to specialized agent groups, enforces safety gates before/after execution, aggregates results with consensus.

